package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/DocumentDrivenDX/ddx/internal/triage"
)

// triageDecisionEventKind is the event kind used to record the triage
// policy's chosen action after a non-APPROVE review verdict.
const triageDecisionEventKind = "triage-decision"

// PostMergeReviewInput bundles the data RunPostMergeReview needs from its
// caller — historically the execute-bead loop body, now the per-attempt
// pipeline owned by try.Attempt (ddx-a921ff01 C3). The fields mirror what
// the inlined block read from the worker, the candidate bead, the report,
// and the loop runtime.
type PostMergeReviewInput struct {
	Bead          bead.Bead
	Report        ExecuteBeadReport
	Reviewer      BeadReviewer
	Store         ExecuteBeadLoopStore
	ProjectRoot   string
	Rcfg          config.ResolvedConfig
	NoReview      bool
	Log           io.Writer
	Assignee      string
	Now           func() time.Time
	ReviewCostCap *escalation.CostCapTracker
}

// PostMergeReviewOutput carries the review state machine's decision back to
// the caller. Report is the (possibly updated) ExecuteBeadReport; Approved
// reports whether the caller should treat this attempt as a success. When
// the review path encountered a non-fatal Store error the caller is expected
// to route StoreErr through its outcome-error handler
// (handleOutcomeStoreError on ExecuteBeadWorker), keyed by StoreErrOp.
type PostMergeReviewOutput struct {
	Report     ExecuteBeadReport
	Approved   bool
	StoreErrOp string
	StoreErr   error
}

// RunPostMergeReview executes the post-merge review state machine for a
// successful bead attempt. When review is skipped (no reviewer or --no-review)
// the bead is closed and the function returns Approved=true. The
// review:skip label only skips when it carries a sibling
// review:skip-reason:* label; otherwise it is ignored. When review is not
// skipped, the reviewer is invoked and its verdict (or error) drives the
// canonical event emissions (review / review-error /
// review-manual-required / review-malfunction), and on a non-APPROVE verdict
// the bead is reopened and the triage policy is consulted via the private
// applyReviewTriageDecision callout that previously lived as a method on
// ExecuteBeadWorker.
//
// Returns Approved=true on the APPROVE path and on the skip path; returns
// Approved=false on REQUEST_CHANGES, BLOCK, malformed BLOCK, or reviewer
// transport error. Store errors are surfaced via StoreErrOp + StoreErr so
// callers can keep the existing handleOutcomeStoreError pattern unchanged.
//
// This is the C3 (ddx-a921ff01) extraction of the 180-line review block
// previously inline in execute_bead_loop.go; the loop now sees a structured
// outcome and conflict-recovery / decomposition / no_changes paths remain
// in the loop body until subsequent C-series beads (C4, C5) move them too.
func RunPostMergeReview(ctx context.Context, in PostMergeReviewInput) PostMergeReviewOutput {
	report := in.Report
	out := PostMergeReviewOutput{Report: report, Approved: true}

	now := in.Now
	if now == nil {
		now = time.Now
	}

	reviewSkipped := in.Reviewer == nil || in.NoReview
	if !reviewSkipped && HasBeadLabel(in.Bead.Labels, "review:skip") {
		reviewSkipped = HasBeadLabelPrefix(in.Bead.Labels, "review:skip-reason:")
	}

	if reviewSkipped {
		if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
			out.StoreErrOp = "CloseWithEvidence"
			out.StoreErr = err
			return out
		}
		out.Report = report
		return out
	}

	implRouting := ImplementerRouting{
		Harness:     report.Harness,
		Provider:    report.Provider,
		Model:       report.Model,
		ActualPower: report.ActualPower,
		Correlation: map[string]string{
			"bead_id":    in.Bead.ID,
			"attempt_id": report.AttemptID,
			"session_id": report.SessionID,
			"result_rev": report.ResultRev,
		},
	}
	reviewRes, reviewErr := in.Reviewer.ReviewBead(ctx, in.Bead.ID, report.ResultRev, implRouting)
	if reviewErr != nil {
		// FEAT-022 §12+§14: classify the failure into the four-class
		// taxonomy and count prior review-error events scoped to the
		// current result_rev. On the Nth failure emit a terminal
		// review-manual-required event instead of yet another
		// review-error, parking the bead so a subsequent loop
		// iteration does NOT re-execute primary.
		class := ClassifyReviewError(reviewErr, reviewRes)
		prior := CountPriorReviewErrors(in.Store, in.Bead.ID, report.ResultRev)
		attemptCount := prior + 1
		maxRetries := in.Rcfg.ReviewMaxRetries()
		if maxRetries <= 0 {
			maxRetries = DefaultReviewMaxRetries
		}
		errSummary := EventBodySummary{
			InputBytes:  0,
			OutputBytes: 0,
		}
		if reviewRes != nil {
			errSummary = EventBodySummary{
				Harness:     reviewRes.ReviewerHarness,
				Model:       reviewRes.ReviewerModel,
				InputBytes:  reviewRes.InputBytes,
				OutputBytes: reviewRes.OutputBytes,
				ElapsedMS:   reviewRes.DurationMS,
			}
		}
		if attemptCount >= maxRetries {
			body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "review-manual-required",
				Summary:   class,
				Body:      body,
				Actor:     in.Assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: now().UTC(),
			})
			// Park the bead with a long cooldown so subsequent
			// loop iterations do NOT re-pick it for primary
			// re-execution. Reviewer-failure invariant (§13) is
			// preserved: the bead is NOT closed.
			parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
			_ = in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, "review-manual-required", class)
		} else {
			body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "review-error",
				Summary:   class,
				Body:      body,
				Actor:     in.Assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: now().UTC(),
			})
		}
		out.Report = report
		out.Approved = false
		return out
	}

	report.ReviewVerdict = string(reviewRes.Verdict)
	report.ReviewRationale = reviewRes.Rationale
	// Persist the full reviewer stream as an artifact so the
	// event body never carries the raw stream (ddx-f8a11202).
	// On error the artifact path is empty and the event body
	// still contains the short verdict summary; callers of this
	// loop can recover the full text from the reviewer session
	// log if the artifact write failed.
	artifactPath, artifactErr := PersistReviewerStream(in.ProjectRoot, in.Bead.ID, report.AttemptID, reviewRes.RawOutput)
	if artifactErr != nil && in.Log != nil {
		_, _ = fmt.Fprintf(in.Log, "reviewer stream artifact: %v\n", artifactErr)
	}

	reviewSummary := EventBodySummary{
		Harness:     reviewRes.ReviewerHarness,
		Model:       reviewRes.ReviewerModel,
		InputBytes:  reviewRes.InputBytes,
		OutputBytes: reviewRes.OutputBytes,
		ElapsedMS:   reviewRes.DurationMS,
	}
	if capTracker := in.ReviewCostCap; capTracker != nil {
		capTracker.Add(reviewRes.ReviewerHarness, reviewRes.CostUSD)
		if detail, capped := capTracker.Tripped(); capped {
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "review-cost-deferred",
				Summary:   "review-cost-deferred",
				Body:      ReviewCostDeferredEventBody(report.ResultRev, reviewRes.CostUSD, capTracker.Spent(), capTracker.MaxUSD),
				Actor:     in.Assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: now().UTC(),
			})
			if in.Log != nil {
				_, _ = fmt.Fprintf(in.Log, "review cost cap deferred (%s %s): %s\n", in.Bead.ID, report.ResultRev, detail)
			}
		}
	}
	switch reviewRes.Verdict {
	case VerdictApprove:
		// Approved: record the verdict event and then close.
		// Closure must land AFTER the review event so the
		// gate (ddx-e30e60a9) sees the terminal verdict.
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review",
			Summary:   "APPROVE",
			Body:      AppendEventSummary(ReviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
			Actor:     in.Assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
		if cerr := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); cerr != nil {
			out.Report = report
			out.StoreErrOp = "CloseWithEvidence"
			out.StoreErr = cerr
			return out
		}
	case VerdictRequestChanges:
		// Needs fixes: record the review verdict, then reopen
		// with findings in notes. The review event must land
		// even on non-approve paths so review-outcomes can
		// attribute the rejection to the originating tier.
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "review",
			Summary:   "REQUEST_CHANGES",
			Body:      AppendEventSummary(ReviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
			Actor:     in.Assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
		reopenNotes := reviewRes.Rationale
		if reopenNotes == "" {
			reopenNotes = reviewRes.RawOutput
		}
		if reopenErr := in.Store.Reopen(in.Bead.ID, "review: REQUEST_CHANGES", reopenNotes); reopenErr != nil {
			out.Report = report
			out.StoreErrOp = "Reopen"
			out.StoreErr = reopenErr
			return out
		}
		report.Status = ExecuteBeadStatusReviewRequestChanges
		report.Detail = "post-merge review: REQUEST_CHANGES"
		out.Approved = false
	case VerdictBlock:
		rationale := strings.TrimSpace(reviewRes.Rationale)
		if rationale == "" {
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "review-malfunction",
				Summary:   "BLOCK without rationale",
				Body:      AppendEventSummary(ReviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
				Actor:     in.Assignee,
				Source:    "ddx agent execute-loop",
				CreatedAt: now().UTC(),

package escalation

import (
	"encoding/json"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// --- Local mirrors of agent.ExecuteBeadStatus* so these tests do not import
// the agent package. Their string values must stay in sync with
// cli/internal/agent/execute_bead_status.go; the agent package's
// TestEscalatableStatusesMatchAgentVocab guards against drift for the
// statuses that drive escalation.
const (
	statusExecutionFailed            = "execution_failed"
	statusNoChanges                  = "no_changes"
	statusPostRunCheckFailed         = "post_run_check_failed"
	statusLandConflict               = "land_conflict"
	statusStructuralValidationFailed = "structural_validation_failed"
	statusAlreadySatisfied           = "already_satisfied"
	statusSuccess                    = "success"
)

// --- EscalationSummary ---

// recordingAppender captures events appended by AppendEscalationSummaryEvent
// so tests can assert on the kind, summary, and JSON body.
type recordingAppender struct {
	events []struct {
		id    string
		event bead.BeadEvent
	}
}

func (r *recordingAppender) AppendEvent(id string, event bead.BeadEvent) error {
	r.events = append(r.events, struct {
		id    string
		event bead.BeadEvent
	}{id: id, event: event})
	return nil
}

// TestEscalationSummary exercises the 3-tier escalation scenario from the
// bead: cheap fails, standard fails, smart succeeds. The emitted
// kind:escalation-summary event body must contain all three tier records
// with correct statuses, costs, and a winning_tier/wasted_cost_usd roll-up.
func TestEscalationSummary(t *testing.T) {
	attempts := []TierAttemptRecord{
		{Tier: "cheap", Harness: "agent", Model: "cheap-model", Status: statusExecutionFailed, CostUSD: 0.02, DurationMS: 1200},
		{Tier: "standard", Harness: "codex", Model: "standard-model", Status: statusNoChanges, CostUSD: 0.15, DurationMS: 3400},
		{Tier: "smart", Harness: "claude", Model: "smart-model", Status: statusSuccess, CostUSD: 0.80, DurationMS: 9000},
	}

	summary := BuildEscalationSummary(attempts, "smart")
	require.Equal(t, "smart", summary.WinningTier)
	require.Len(t, summary.TiersAttempted, 3)
	assert.InDelta(t, 0.97, summary.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.17, summary.WastedCostUSD, 1e-9, "cheap (0.02) + standard (0.15) wasted, smart succeeded")
	assert.Equal(t, "cheap", summary.TiersAttempted[0].Tier)
	assert.Equal(t, statusExecutionFailed, summary.TiersAttempted[0].Status)
	assert.Equal(t, statusNoChanges, summary.TiersAttempted[1].Status)
	assert.Equal(t, statusSuccess, summary.TiersAttempted[2].Status)

	// Now wire through AppendEscalationSummaryEvent and verify the emitted
	// event has kind:escalation-summary, a summary line, and a JSON body
	// that round-trips to the same EscalationSummary.
	appender := &recordingAppender{}
	err := AppendEscalationSummaryEvent(appender, "ddx-test-1", "test-actor", attempts, "smart", time.Unix(1, 0).UTC())
	require.NoError(t, err)
	require.Len(t, appender.events, 1)

	ev := appender.events[0]
	assert.Equal(t, "ddx-test-1", ev.id)
	assert.Equal(t, "escalation-summary", ev.event.Kind)
	assert.Equal(t, "test-actor", ev.event.Actor)
	assert.Contains(t, ev.event.Summary, "winning_tier=smart")
	assert.Contains(t, ev.event.Summary, "attempts=3")

	var decoded EscalationSummary
	require.NoError(t, json.Unmarshal([]byte(ev.event.Body), &decoded))
	assert.Equal(t, "smart", decoded.WinningTier)
	require.Len(t, decoded.TiersAttempted, 3)
	assert.Equal(t, "cheap", decoded.TiersAttempted[0].Tier)
	assert.Equal(t, "agent", decoded.TiersAttempted[0].Harness)
	assert.Equal(t, "cheap-model", decoded.TiersAttempted[0].Model)
	assert.Equal(t, statusExecutionFailed, decoded.TiersAttempted[0].Status)
	assert.InDelta(t, 0.02, decoded.TiersAttempted[0].CostUSD, 1e-9)
	assert.Equal(t, int64(1200), decoded.TiersAttempted[0].DurationMS)
	assert.InDelta(t, 0.97, decoded.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.17, decoded.WastedCostUSD, 1e-9)
}

// TestEscalationSummaryExhausted verifies the exhausted case (no tier
// succeeded): winning_tier is "exhausted" and all costs are wasted.
func TestEscalationSummaryExhausted(t *testing.T) {
	attempts := []TierAttemptRecord{
		{Tier: "cheap", Harness: "agent", Model: "c", Status: statusExecutionFailed, CostUSD: 0.01, DurationMS: 900},
		{Tier: "smart", Harness: "claude", Model: "s", Status: statusExecutionFailed, CostUSD: 0.50, DurationMS: 7000},
	}
	summary := BuildEscalationSummary(attempts, "")
	assert.Equal(t, EscalationWinningExhausted, summary.WinningTier)
	assert.InDelta(t, 0.51, summary.TotalCostUSD, 1e-9)
	assert.InDelta(t, 0.51, summary.WastedCostUSD, 1e-9, "every attempt wasted when no tier succeeded")
}

// TestEscalationSummaryBuildSourceSliceIndependent verifies the attempts
// slice in the returned summary is independent of the caller's slice —
// mutating the caller's slice must not change the summary.
func TestEscalationSummaryBuildSourceSliceIndependent(t *testing.T) {
	attempts := []TierAttemptRecord{
		{Tier: "cheap", Status: statusSuccess, CostUSD: 0.05},
	}
	summary := BuildEscalationSummary(attempts, "cheap")
	attempts[0].Tier = "mutated"
	assert.Equal(t, "cheap", summary.TiersAttempted[0].Tier, "summary must hold an independent copy of attempts")
}

// --- ShouldEscalate ---

func TestShouldEscalateExecutionFailed(t *testing.T) {
	assert.True(t, ShouldEscalate(statusExecutionFailed))
}

func TestShouldEscalateNoChangesIsFalse(t *testing.T) {
	assert.False(t, ShouldEscalate(statusNoChanges))
}

func TestShouldEscalatePostRunCheckFailed(t *testing.T) {
	assert.True(t, ShouldEscalate(statusPostRunCheckFailed))
}

func TestShouldEscalateLandConflict(t *testing.T) {
	assert.True(t, ShouldEscalate(statusLandConflict))
}

func TestShouldEscalateSuccessIsFalse(t *testing.T) {
	assert.False(t, ShouldEscalate(statusSuccess))
}

func TestShouldEscalateStructuralValidationIsTrue(t *testing.T) {
	assert.True(t, ShouldEscalate(statusStructuralValidationFailed))
}

func TestShouldEscalateAlreadySatisfiedIsFalse(t *testing.T) {
	assert.False(t, ShouldEscalate(statusAlreadySatisfied))
}

// --- FormatTierAttemptBody ---

func TestFormatTierAttemptBodyWithAllFields(t *testing.T) {
	body := FormatTierAttemptBody("cheap", "claude", "claude-haiku-4-5", "ok", "execution failed")
	assert.Contains(t, body, "tier=cheap")
	assert.Contains(t, body, "harness=claude")
	assert.Contains(t, body, "model=claude-haiku-4-5")
	assert.Contains(t, body, "probe=ok")
	assert.Contains(t, body, "execution failed")
}

func TestFormatTierAttemptBodyNoProbeNoDetail(t *testing.T) {
	body := FormatTierAttemptBody("standard", "codex", "gpt-5.4", "", "")
	assert.Contains(t, body, "tier=standard")
	assert.NotContains(t, body, "probe=")
}

